import{_ as l,o as i,c as e,a2 as r}from"./chunks/framework.ZhLefgN8.js";const b=JSON.parse('{"title":"到价反弹订单","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/order-types/bounce-order.md","filePath":"zh-CN/stock-trading/order-types/bounce-order.md"}'),t={name:"stock-trading/order-types/bounce-order.md"};function o(h,a,d,n,u,c){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="到价反弹订单" tabindex="-1">到价反弹订单 <a class="header-anchor" href="#到价反弹订单" aria-label="Permalink to &quot;到价反弹订单&quot;">​</a></h1><p>条件订单是在满足特定价格条件时自动触发委托的订单类型，适用于止盈、止损等场景。</p><hr><h2 id="到价买入-buy-if-touched" tabindex="-1">到价买入（Buy if Touched） <a class="header-anchor" href="#到价买入-buy-if-touched" aria-label="Permalink to &quot;到价买入（Buy if Touched）&quot;">​</a></h2><p>设定触发价格，当市价达到该价格后，系统自动提交买入订单。</p><h3 id="参数设置" tabindex="-1">参数设置 <a class="header-anchor" href="#参数设置" aria-label="Permalink to &quot;参数设置&quot;">​</a></h3><ul><li>触发条件：监控行情价格达到设定条件后触发委托单</li><li>市价到达：不能等于当前价格。设置价格 &gt; 当前最新价时，最新价涨过设置价格就触发；设置价格 &lt; 当前最新价时，最新价跌过设置价格就触发</li><li>委托类型：限价单或市价单</li><li>支持订单有效期：当日有效 / 撤销前有效 / 特定日期前有效</li></ul><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><ul><li>当前最新价 191，设置市价达到 190.07 → 当最新价 ≤ 190.07 时触发买入</li><li>当前最新价 191，设置市价达到 191.07 → 当最新价 ≥ 191.07 时触发买入</li></ul><p>适用场景：空头持仓的止盈或止损。</p><hr><h2 id="到价卖出-sell-if-touched" tabindex="-1">到价卖出（Sell if Touched） <a class="header-anchor" href="#到价卖出-sell-if-touched" aria-label="Permalink to &quot;到价卖出（Sell if Touched）&quot;">​</a></h2><p>设定触发价格，当市价达到该价格后，系统自动提交卖出订单。</p><h3 id="参数设置-1" tabindex="-1">参数设置 <a class="header-anchor" href="#参数设置-1" aria-label="Permalink to &quot;参数设置&quot;">​</a></h3><ul><li>触发条件：同到价买入</li><li>委托类型：限价单或市价单</li><li>支持订单有效期：当日有效 / 撤销前有效 / 特定日期前有效</li></ul><h3 id="示例-1" tabindex="-1">示例 <a class="header-anchor" href="#示例-1" aria-label="Permalink to &quot;示例&quot;">​</a></h3><ul><li>当前最新价 160，设置市价达到 169.71 → 当最新价 ≥ 169.71 时触发卖出</li><li>当前最新价 160，设置市价达到 150.00 → 当最新价 ≤ 150.00 时触发卖出</li></ul><p>适用场景：多头持仓的止盈或止损。</p><hr><h2 id="反弹买入-trailing-to-buy" tabindex="-1">反弹买入（Trailing to Buy） <a class="header-anchor" href="#反弹买入-trailing-to-buy" aria-label="Permalink to &quot;反弹买入（Trailing to Buy）&quot;">​</a></h2><p>设定监控价格，当市场价格跌破监控价格后，系统开始跟踪价格反弹幅度。当反弹幅度达到设定条件时，自动提交买入委托单。</p><h3 id="参数设置-2" tabindex="-1">参数设置 <a class="header-anchor" href="#参数设置-2" aria-label="Permalink to &quot;参数设置&quot;">​</a></h3><ul><li>跟踪类型：涨幅（百分比）或涨额（价格金额）</li><li>委托价格（触发时市价+）：输入 0 表示以当时市价委托，输入数字表示在市价基础上加价差以确保成交</li><li>支持订单有效期：当日有效 / 撤销前有效 / 特定日期前有效</li></ul><h3 id="示例-2" tabindex="-1">示例 <a class="header-anchor" href="#示例-2" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p>设置监控价格 100，跟踪类型涨额 = 10，触发时市价 + = 1，下单时市价 = 100：</p><ol><li>110 → 105：未满足监控价格条件</li><li>105 → 99：满足监控条件（跌破 100），开始监控反弹幅度</li><li>99 → 95：记录最低点 95</li><li>95 → 104：距最低点 95 反弹涨额 = 9，不满足，不触发</li><li>104 → 90：更新最低点为 90</li><li>90 → 100：距最低点 90 反弹涨额 = 10，满足条件，触发：以市价 100 + 1 = 101 下达买入限价单</li></ol><hr><h2 id="回落卖出-trailing-to-sell" tabindex="-1">回落卖出（Trailing to Sell） <a class="header-anchor" href="#回落卖出-trailing-to-sell" aria-label="Permalink to &quot;回落卖出（Trailing to Sell）&quot;">​</a></h2><p>设定监控价格，当市场价格涨破监控价格后，系统开始跟踪价格回落幅度。当回落幅度达到设定条件时，自动提交卖出委托单。</p><h3 id="参数设置-3" tabindex="-1">参数设置 <a class="header-anchor" href="#参数设置-3" aria-label="Permalink to &quot;参数设置&quot;">​</a></h3><ul><li>跟踪类型：跌幅（百分比）或跌额（价格金额）</li><li>委托价格（触发时市价-）：输入 0 表示以当时市价委托，输入数字表示在市价基础上减价差以确保成交</li><li>支持订单有效期：当日有效 / 撤销前有效 / 特定日期前有效</li></ul><h3 id="示例-3" tabindex="-1">示例 <a class="header-anchor" href="#示例-3" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p>设置监控价格 100，跟踪类型跌幅 = 10%，触发时市价 - = 0，下单时市价 = 100：</p><ol><li>90 → 95：未满足监控价格条件</li><li>95 → 101：满足监控条件（涨破 100），开始监控回落幅度</li><li>101 → 105：记录最高点 105</li><li>105 → 100：距最高点 105 回落 4.76%，不满足，不触发</li><li>100 → 110：更新最高点为 110</li><li>110 → 99：距最高点 110 回落 10%，满足条件，触发：以市价 99 - 0 = 99 下达卖出限价单</li></ol><hr><h2 id="行情数据源与系统限制" tabindex="-1">行情数据源与系统限制 <a class="header-anchor" href="#行情数据源与系统限制" aria-label="Permalink to &quot;行情数据源与系统限制&quot;">​</a></h2><ul><li>系统以特定行情数据作为价格监控标准。美股使用全美行情，Basic 行情表现与全美行情有差异</li><li>条件订单在触发前以预埋单方式暂存于系统，可能因系统升级、公司行动或其他不可控因素被取消</li><li>建议定期检查已设置的条件订单，确保交易计划不受影响</li></ul>',37)])])}const p=l(t,[["render",o]]);export{b as __pageData,p as default};
